const apiResponse = $json;
const passStateData = $('Pass State').item.json;

const prevCompanies = passStateData.allCompanies || [];
const newCompanies = apiResponse.results || [];
const cursor = apiResponse.paging?.next?.after || null;

return {
  json: {
    after: cursor,
    allCompanies: [...prevCompanies, ...newCompanies]
  }
};

const allCompanies = $input.first().json.allCompanies || [];
return allCompanies.map(company => ({
  json: {
    id: String(company.id),
    properties: company.properties || {}
  }
}));

const geminiResponse = $input.first().json;
const prepData = $('Prepare Gemini Batch').first().json;
const companyData = JSON.parse(prepData.companyData);

let classifications = [];
try {
  const text = geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  classifications = JSON.parse(cleaned);
} catch (e) {
  classifications = companyData.map((_, i) => ({
    index: i,
    isSubsidiary: false,
    confidence: null,
    parentCompany: null,
    parentDomain: null
  }));
}

return companyData.map((company, index) => {
  const classification = classifications.find(c => c.index === index) || {
    isSubsidiary: false,
    confidence: null,
    parentCompany: null,
    parentDomain: null
  };

  // Block self-referencing: parent cannot be the same as the company
  const isSelfRef = classification.isSubsidiary &&
    classification.parentCompany &&
    classification.parentCompany.toLowerCase().trim() === company.companyName.toLowerCase().trim();

  if (isSelfRef) {
    classification.isSubsidiary = false;
    classification.confidence = null;
    classification.parentCompany = null;
    classification.parentDomain = null;
  }

  return {
    json: {
      companyId: company.companyId,
      companyName: company.companyName,
      domain: company.domain,
      linkedinUrl: company.linkedinUrl,
      existingEmployeeCount: company.existingEmployeeCount,
      existingGroupEmployeeCount: company.existingGroupEmployeeCount || 0,
      isSubsidiary: classification.isSubsidiary || false,
      confidence: classification.confidence || null,
      parentCompany: classification.parentCompany || null,
      parentDomain: classification.parentDomain || null
    }
  };
});

const items = $input.all();
const allCompanyData = [];
const domainSet = new Set();

for (const item of items) {
  const d = item.json;
  const needsEmployeeCount = d.existingEmployeeCount <= 0;
  const isSubsidiary = d.isSubsidiary === true;

  // Track A: no employee count -> enrich own count
  // Track B: HAS employee count AND is subsidiary -> enrich group level
  // Never both
  const trackA = needsEmployeeCount;
  const trackB = !needsEmployeeCount && isSubsidiary;

  // Track B: skip Amplemarket if parent already has employee count in HubSpot
  const parentAlreadyResolved = trackB && d.parentEmployeeCount > 0;

  allCompanyData.push({
    ...d,
    needsEmployeeCount,
    trackA,
    trackB,
    parentAlreadyResolved
  });

  // Track A: company's own domain
  if (trackA && d.domain) {
    domainSet.add(d.domain.toLowerCase());
  }

  // Track B: parent domain — only if NOT already resolved from HubSpot
  if (trackB && d.parentDomain && !parentAlreadyResolved) {
    domainSet.add(d.parentDomain.toLowerCase());
  }
}

const companies = [...domainSet].map(domain => ({ domain }));

return [{
  json: {
    batchPayload: { companies },
    allCompanyData: JSON.stringify(allCompanyData),
    totalCompanies: allCompanyData.length,
    batchSize: companies.length,
    uniqueDomains: companies.length
  }
}];

const submitResponse = $json;
const batchData = $('Build Batch Request').first().json;

return {
  json: {
    requestId: submitResponse.id || submitResponse.request_id || submitResponse.data?.id || '',
    pollCount: 0,
    maxPolls: 20,
    allCompanyData: batchData.allCompanyData,
    totalCompanies: batchData.totalCompanies
  }
};

const apiResponse = $json;
const state = $('Wait 15s').item.json;

const isCompleted = apiResponse.status === 'completed' || apiResponse.data?.status === 'completed';
const pollCount = (state.pollCount || 0) + 1;
const maxReached = pollCount >= (state.maxPolls || 20);

return {
  json: {
    pollResponse: apiResponse,
    requestId: state.requestId,
    pollCount,
    maxPolls: state.maxPolls || 20,
    allCompanyData: state.allCompanyData,
    totalCompanies: state.totalCompanies,
    isComplete: isCompleted || maxReached
  }
};

return {
  json: {
    requestId: $json.requestId,
    pollCount: $json.pollCount,
    maxPolls: $json.maxPolls,
    allCompanyData: $json.allCompanyData,
    totalCompanies: $json.totalCompanies
  }
};

const input = $input.first().json;
const pollResponse = input.pollResponse || input;
const allCompanyData = JSON.parse(input.allCompanyData || '[]');
const results = pollResponse.results || [];

// Build domain lookup from Amplemarket results
const resultsByDomain = {};
for (const r of results) {
  if (r.domain) {
    const empCount = (r.result && typeof r.result === 'object')
      ? (r.result.estimated_number_of_employees || 0)
      : (r.estimated_number_of_employees || 0);
    resultsByDomain[r.domain.toLowerCase()] = empCount;
  }
}

return allCompanyData.map(company => {
  const isTrackA = company.trackA;
  const isTrackB = company.trackB;

  // Track A: employee count from company's own domain
  let employeeCount = null;
  let enrichmentSource = null;
  if (isTrackA) {
    const ownDomainCount = company.domain ? (resultsByDomain[company.domain.toLowerCase()] || 0) : 0;
    if (ownDomainCount > 0) {
      employeeCount = ownDomainCount;
      enrichmentSource = 'Amplemarket';
    } else {
      employeeCount = 5;
      enrichmentSource = 'Estimated';
    }
  }

  // Track B: group employee count (only for companies that HAVE their own count)
  let groupEmployeeCount = null;
  let groupSource = null;
  let updateGroupCount = false;
  if (isTrackB) {
    if (company.parentAlreadyResolved && company.parentEmployeeCount > 0) {
      groupEmployeeCount = company.parentEmployeeCount;
      groupSource = 'HubSpot';
    } else if (company.parentDomain) {
      const parentDomainCount = resultsByDomain[company.parentDomain.toLowerCase()] || 0;
      if (parentDomainCount > 0) {
        groupEmployeeCount = parentDomainCount;
        groupSource = 'Amplemarket';
      }
    }
    // Only write if group count > company's own count
    updateGroupCount = groupEmployeeCount !== null && groupEmployeeCount > company.existingEmployeeCount;
  }

  return {
    json: {
      companyId: company.companyId,
      companyName: company.companyName,
      domain: company.domain,
      isSubsidiary: company.isSubsidiary || false,
      confidence: company.confidence || null,
      parentCompany: company.parentCompany || '',
      parentCompanyValue: company.parentCompanyValue || '',
      parentDomain: company.parentDomain || '',
      existingEmployeeCount: company.existingEmployeeCount || 0,
      employeeCount,
      enrichmentSource,
      groupEmployeeCount,
      groupSource,
      updateEmployeeCount: isTrackA,
      updateGroupCount
    }
  };
});

const r = $('Preserve Pre-Update').item.json;
return {
  json: {
    companyId: r.companyId,
    companyName: r.companyName,
    domain: r.domain,
    isSubsidiary: r.isSubsidiary,
    confidence: r.confidence || '',
    parentCompany: r.parentCompany,
    parentCompanyValue: r.parentCompanyValue || '',
    employeeCount: r.employeeCount,
    enrichmentSource: r.enrichmentSource,
    existingEmployeeCount: r.existingEmployeeCount || 0,
    groupEmployeeCount: r.groupEmployeeCount,
    groupSource: r.groupSource || '',
    updateEmployeeCount: r.updateEmployeeCount,
    updateGroupCount: r.updateGroupCount
  }
};

const items = $json.data || [];

if (items.length === 0) {
  return { json: { message: 'No companies processed for employee enrichment today.' } };
}

const today = new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });
let trackAAmplemarket = 0;
let trackAEstimated = 0;
let trackBWritten = 0;
let trackBSkipped = 0;
let trackBTooSmall = 0;
const detailsA = [];
const detailsB = [];
const reviewItems = [];

for (const d of items) {
  const name = d.companyName || d.domain || 'unknown';

  if (d.updateEmployeeCount) {
    if (d.enrichmentSource === 'Estimated') {
      trackAEstimated++;
      detailsA.push('  \u26aa ' + name + ' \u2192 5 (default)');
    } else {
      trackAAmplemarket++;
      detailsA.push('  \u2705 ' + name + ' \u2192 ' + d.employeeCount);
    }
  }

  if (d.isSubsidiary && d.existingEmployeeCount > 0) {
    const parentLink = d.parentCompanyValue && d.parentCompanyValue.startsWith('https')
      ? '<' + d.parentCompanyValue + '|' + d.parentCompany + '>'
      : (d.parentCompany || 'unknown');

    const written = d.confidence === 'high' || (d.confidence === 'medium' && d.groupSource === 'HubSpot');

    if (!written) {
      trackBSkipped++;
      reviewItems.push('  \u2022 ' + name + ' \u2192 ' + parentLink);
    } else if (d.groupEmployeeCount && d.groupEmployeeCount <= d.existingEmployeeCount) {
      trackBTooSmall++;
      detailsB.push('  \u26aa ' + name + ' \u2192 skipped, group (' + d.groupEmployeeCount + ') \u2264 company (' + d.existingEmployeeCount + ')');
    } else if (d.updateGroupCount && d.groupEmployeeCount > 0) {
      trackBWritten++;
      const src = d.groupSource === 'HubSpot' ? 'from HubSpot' : 'from Amplemarket';
      const confLabel = d.confidence === 'medium' ? ' (medium, validated by HubSpot)' : '';
      detailsB.push('  \u2705 ' + name + ' \u2192 ' + d.groupEmployeeCount + ' group emp. (' + src + ', parent: ' + parentLink + ')' + confLabel);
    } else {
      detailsB.push('  \u26aa ' + name + ' \u2192 no data (parent: ' + parentLink + ')');
    }
  }
}

const totalA = trackAAmplemarket + trackAEstimated;

let message = '*Employee Enrichment v4.0* \u2014 ' + today + '\n';

if (totalA > 0) {
  message += '\n*Track A \u2014 Employee Count* (' + totalA + ')\n';
  message += 'Amplemarket: ' + trackAAmplemarket + ' \u2022 Default: ' + trackAEstimated + '\n';
  message += detailsA.slice(0, 30).join('\n') + '\n';
}

if (detailsB.length > 0) {
  message += '\n*Track B \u2014 Group Employee Count* (' + trackBWritten + ' written)\n';
  message += detailsB.slice(0, 30).join('\n') + '\n';
}

if (reviewItems.length > 0) {
  message += '\n*\u26a0\ufe0f Needs review* (' + trackBSkipped + ' medium confidence, parent not in HubSpot)\n';
  message += reviewItems.join('\n') + '\n';
}

if (totalA === 0 && detailsB.length === 0 && reviewItems.length === 0) {
  message += '\nNo enrichments needed today.';
}

return { json: { message } };

const items = $input.all();
const parentDomains = new Set();
const allCompanyData = [];

for (const item of items) {
  const d = item.json;
  allCompanyData.push(d);
  if (d.isSubsidiary && d.parentDomain) {
    parentDomains.add(d.parentDomain);
  }
}

const domains = [...parentDomains];
let searchBody;
if (domains.length > 0) {
  searchBody = {
    filterGroups: [{ filters: [{ propertyName: 'domain', operator: 'IN', values: domains }] }],
    properties: ['name', 'domain', 'numberofemployees'],
    limit: 100
  };
} else {
  searchBody = {
    filterGroups: [{ filters: [{ propertyName: 'domain', operator: 'EQ', value: '__no_parent_domains__' }] }],
    properties: ['name', 'domain', 'numberofemployees'],
    limit: 1
  };
}

return [{
  json: {
    parentDomains: domains,
    allCompanyData: JSON.stringify(allCompanyData),
    hasParents: domains.length > 0,
    searchBody: JSON.stringify(searchBody)
  }
}];

const input = $input.first().json;
const prepData = $('Prep Parent Lookup').first().json;
const allCompanyData = JSON.parse(prepData.allCompanyData);

const hsResults = input.results || [];

// Build lookup: domain -> { url, employeeCount }
const parentByDomain = {};
for (const r of hsResults) {
  const domain = (r.properties && r.properties.domain || '').toLowerCase();
  const companyId = r.id;
  const empCount = parseInt(r.properties?.numberofemployees) || 0;
  if (domain && companyId) {
    parentByDomain[domain] = {
      url: 'https://app-eu1.hubspot.com/contacts/142047914/company/' + companyId,
      employeeCount: empCount
    };
  }
}

return allCompanyData.map(company => {
  let parentCompanyValue = '';
  let parentEmployeeCount = 0;

  if (company.isSubsidiary && company.parentCompany) {
    const parentKey = (company.parentDomain || '').toLowerCase();
    const parentData = parentByDomain[parentKey];
    if (parentData) {
      parentCompanyValue = parentData.url;
      parentEmployeeCount = parentData.employeeCount;
    } else {
      parentCompanyValue = company.parentCompany;
    }
  }

  return {
    json: {
      companyId: company.companyId,
      companyName: company.companyName,
      domain: company.domain,
      linkedinUrl: company.linkedinUrl || '',
      existingEmployeeCount: company.existingEmployeeCount || 0,
      existingGroupEmployeeCount: company.existingGroupEmployeeCount || 0,
      isSubsidiary: company.isSubsidiary || false,
      confidence: company.confidence || null,
      parentCompany: company.parentCompany || null,
      parentDomain: company.parentDomain || null,
      parentEmployeeCount,
      enrichmentDomain: company.enrichmentDomain || company.domain,
      parentCompanyValue
    }
  };
});

const d = $json;
const properties = {};

// Track A: employee count
if (d.updateEmployeeCount) {
  properties.numberofemployees = String(d.employeeCount);
  properties['number-employees-enrichment-source'] = d.enrichmentSource;
}

// Track B: group-level data
// Write if HIGH confidence, or MEDIUM confidence with parent validated by HubSpot
const writeTrackB = d.isSubsidiary && (
  d.confidence === 'high' ||
  (d.confidence === 'medium' && d.groupSource === 'HubSpot')
);

if (writeTrackB) {
  properties.is_subsidiary = 'true';
  properties.parent_company_name = d.parentCompanyValue || d.parentCompany || '';
  if (d.updateGroupCount && d.groupEmployeeCount > 0) {
    properties.group_number_of_employees = String(d.groupEmployeeCount);
  }
}

// Skip if nothing to update
if (Object.keys(properties).length === 0) {
  return { json: { ...d, skipped: true } };
}

const response = await this.helpers.httpRequestWithAuthentication.call(this, 'hubspotAppToken', {
  method: 'PATCH',
  url: `https://api.hubapi.com/crm/v3/objects/companies/${d.companyId}`,
  body: { properties },
  json: true
});

return { json: { ...d, hubspotResponse: response.id || 'updated' } };
